import{_ as e,y as o,x as a,W as s}from"./plugin-vue_export-helper.05763f57.js";const f='{"title":"Install","description":"","frontmatter":{"sidebar":true},"headers":[{"level":2,"title":"Install","slug":"install"},{"level":2,"title":"Setup","slug":"setup"},{"level":3,"title":"Register to Arcsecond.io","slug":"register-to-arcsecond-io"},{"level":3,"title":"Login to Arcsecond.io","slug":"login-to-arcsecond-io"}],"relativePath":"install/index.md","lastUpdated":1711350920126}',r={},n=s(`<h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-hidden="true">#</a></h2><p>Simply issue the following in a Terminal:</p><div class="language-bash"><pre><code>$ pip <span class="token function">install</span> arcsecond
</code></pre></div><p>To upgrade an existing Arcsecond installation:</p><div class="language-bash"><pre><code>$ pip <span class="token function">install</span> --upgrade arcsecond
</code></pre></div><p>The help is accessible like any other command line:</p><div class="language-bash"><pre><code>$ arcsecond --help
</code></pre></div><p>or, for subcommand</p><div class="language-bash"><pre><code>$ arcsecond <span class="token operator">&lt;</span>command<span class="token operator">&gt;</span> --help
</code></pre></div><p>At that point, you can access all the public resources of <a href="http://Arcsecond.io" target="_blank" rel="noopener noreferrer">Arcsecond.io</a>.</p><p>The Arcsecond CLI usage is similar to a utility like <code>git</code>. That is, <code>arcsecond</code> is the main entry point, followed by a command. Most of the commands are simply the name of API resources.</p><p>For accessing private resources, such as datasets, night logs etc, you must log in (or register first).</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-hidden="true">#</a></h2><h3 id="register-to-arcsecond-io" tabindex="-1">Register to <a href="http://Arcsecond.io" target="_blank" rel="noopener noreferrer">Arcsecond.io</a> <a class="header-anchor" href="#register-to-arcsecond-io" aria-hidden="true">#</a></h3><p>You can register directly from the CLI:</p><div class="language-bash"><pre><code>$ arcsecond register
</code></pre></div><p>and provide a username and a password.</p><h3 id="login-to-arcsecond-io" tabindex="-1">Login to <a href="http://Arcsecond.io" target="_blank" rel="noopener noreferrer">Arcsecond.io</a> <a class="header-anchor" href="#login-to-arcsecond-io" aria-hidden="true">#</a></h3><p><strong>You must login first before accessing APIs.</strong></p><div class="language-bash"><pre><code>$ arcsecond login 
</code></pre></div><p>To skip prompts:</p><div class="language-bash"><pre><code>$ arcsecond login --username <span class="token operator">&lt;</span>username<span class="token operator">&gt;</span> --password <span class="token operator">&lt;</span>password<span class="token operator">&gt;</span>
</code></pre></div><p>By registering or logging in, <strong>your private API key will be stored locally</strong> in the config file in <code>~/.arcsecond.ini</code>. <strong>Do not share this key. It gives a complete access to your private resources too.</strong></p><p>Logging in again will overwrite the current API key with the new one (assuming login is a success, of course).</p><p>If you think your key is compromised, you can regenerate one in your profile settings in <a href="https://www.arcsecond.io" target="_blank" rel="noopener noreferrer">https://www.arcsecond.io</a>. You cannot regenerate an API key with the cli.</p>`,25),t=[n];function i(c,l,p,d,g,h){return a(),o("div",null,t)}var m=e(r,[["render",i]]);export{f as __pageData,m as default};
